{{
  (() => {
    const dados = _VariacaoConversas.data[0]; // pega o primeiro resultado
    const variacao = dados.variacao_percentual;

    // monta mensagem amigável
    if (variacao > 0) {
      return `Hoje (${dados.data_atual}) houve um aumento de ${variacao}% em relação ao pico (${dados.data_maxima}).`;
    } else if (variacao < 0) {
      return `Hoje (${dados.data_atual}) houve uma queda de ${Math.abs(variacao)}% em relação ao pico (${dados.data_maxima}).`;
    } else {
      return `Hoje (${dados.data_atual}) está igual ao pico (${dados.data_maxima}), sem variação.`;
    }
  })()
}}
